async (params, browser) => {
  // Open author profile
  await browser.open(`https://medium.com/@${params.username}`)

  // Wait for profile page to load
  await browser.waitForSelector('h1, h2, [class*=\'profile\'], [class*=\'hero\']', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load articles
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract author profile
  const author_data = await browser.evaluate(`const nameEl = document.querySelector('h1, h2[class*="name"], [class*="profile"] h1, [class*="hero"] h1'); const bioEl = document.querySelector('[class*="bio"], [class*="profile"] p, [class*="about"] p, [class*="description"]'); const followersEl = document.querySelector('a[href*="followers"] span, [class*="follower"] span, [class*="followerCount"]'); const followingEl = document.querySelector('a[href*="following"] span, [class*="following"] span'); const avatarEl = document.querySelector('img[class*="avatar"], img[class*="profile"], [class*="hero"] img'); const articles = []; const articleEls = document.querySelectorAll('article, [data-testid="postPreview"], div[class*="postArticle"]'); for (let i = 0; i < Math.min(articleEls.length, 10); i++) { const el = articleEls[i]; const titleEl = el.querySelector('h2, h3, [class*="title"]'); const clapsEl = el.querySelector('[class*="clap"] span, button[data-testid="clap"] span'); const dateEl = el.querySelector('time, span[class*="date"]'); const readTimeEl = el.querySelector('[class*="readingTime"], span[class*="read-time"]'); const linkEl = el.querySelector('a[href*="/p/"], a[data-testid="postPreview-title"], h2 a, h3 a'); articles.push({ title: titleEl ? titleEl.textContent.trim() : '', claps: clapsEl ? clapsEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', read_time: readTimeEl ? readTimeEl.textContent.trim() : '', url: linkEl ? linkEl.href : '' }); } return { name: nameEl ? nameEl.textContent.trim() : '' + params.username + '', bio: bioEl ? bioEl.textContent.trim().substring(0, 500) : '', followers: followersEl ? followersEl.textContent.trim() : '', following: followingEl ? followingEl.textContent.trim() : '', avatar: avatarEl ? avatarEl.getAttribute('src') : '', article_count: articles.length, articles: articles, profile_url: window.location.href }`)

  return author_data
}
